module top_module(
  input wire [3:0] in_data,
  input wire reset,
  output wire [2:0] out_data
);reg [2:0] inverted_out_data;

  always @(*) begin
    if (reset) begin
      inverted_out_data <= 3'b0;
    end else begin
      inverted_out_data <= in_data + 3'b010;
    end
  end

  assign out_data = inverted_out_data;

endmodule
